import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useData } from '../context/DataContext';

const LoginForm = () => {
  const [form, setForm] = useState({ user: '', pass: '' });
  const { login } = useAuth();
  const { staffList } = useData();
  const navigate = useNavigate();

  const handleSubmit = (e) => {
    e.preventDefault();
    // Admin login cứng (hoặc có thể đưa vào data nếu muốn)
    if (form.user === 'admin' && form.pass === 'admin') {
      login({ name: 'Chief Admin', role: 'admin' });
      navigate('/admin/staff-manager');
    } else {
      // Tìm trong danh sách nhân sự từ DataContext
      const staff = staffList.find(s => s.username === form.user && s.password === form.pass);
      
      if (staff) {
        if (staff.status === 'suspended') {
            alert('Tài khoản của bạn đang bị tạm khóa. Vui lòng liên hệ Admin.');
            return;
        }
        login(staff);
        navigate('/staff/attendance');
      } else {
        alert('Sai tên đăng nhập hoặc mật khẩu!');
      }
    }
  };

  return (
    <div style={{ 
      display: 'flex', 
      justifyContent: 'center', 
      alignItems: 'center', 
      height: '100vh', 
      background: '#f0f2f5' 
    }}>
      <div style={{ 
        padding: '40px', 
        background: 'white', 
        borderRadius: '10px', 
        boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
        width: '100%',
        maxWidth: '400px',
        textAlign: 'center'
      }}>
        <h2 style={{ color: '#003366', marginBottom: '30px' }}>Đăng nhập Hệ thống</h2>
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <input 
            placeholder="Tên đăng nhập" 
            value={form.user}
            onChange={e => setForm({...form, user: e.target.value})} 
            style={{ padding: '12px', borderRadius: '5px', border: '1px solid #ccc', fontSize: '16px' }}
          />
          <input 
            type="password" 
            placeholder="Mật khẩu" 
            value={form.pass}
            onChange={e => setForm({...form, pass: e.target.value})} 
            style={{ padding: '12px', borderRadius: '5px', border: '1px solid #ccc', fontSize: '16px' }}
          />
          <button 
            type="submit"
            style={{ 
              padding: '12px', 
              background: '#003366', 
              color: 'white', 
              border: 'none', 
              borderRadius: '5px', 
              fontSize: '16px', 
              fontWeight: 'bold', 
              cursor: 'pointer',
              marginTop: '10px'
            }}
          >
            ĐĂNG NHẬP
          </button>
        </form>
      </div>
    </div>
  );
};

export default LoginForm;
